diff --git a/packages/components/components/drawer/views/SecurityCenter/PassAliases/test/PassAliasesProvider.blockers.test.tsx b/packages/components/components/drawer/views/SecurityCenter/PassAliases/test/PassAliasesProvider.blockers.test.tsx
