@@ -0,0 +1,122 @@
+import { UNIX_MINUTE } from '@proton/pass/utils/time/constants';
+
+const mockRequestShares = jest.fn();
+const mockCreateVault = jest.fn();
+const mockParseShareResponse = jest.fn();
+const mockObservedMaxAges: Array<number | undefined> = [];
+const mockCallOrder: string[] = [];
+
+jest.mock('@proton/pass/lib/alias/alias.requests', () => ({
+    getAliasOptions: jest.fn(),
+}));
+jest.mock('@proton/pass/lib/api/api', () => ({
+    exposeApi: jest.fn(),
+}));
+jest.mock('@proton/pass/lib/crypto', () => ({
+    exposePassCrypto: jest.fn(() => ({
+        hydrate: jest.fn().mockResolvedValue(undefined),
+        ready: true,
+    })),
+}));
+jest.mock('@proton/pass/lib/crypto/pass-crypto', () => ({
+    createPassCrypto: jest.fn(() => ({})),
+}));
+jest.mock('@proton/pass/lib/items/item.parser', () => ({
+    parseItemRevision: jest.fn(),
+}));
+jest.mock('@proton/pass/lib/items/item.requests', () => ({
+    createAlias: jest.fn(),
+    requestAllItemsForShareId: jest.fn().mockResolvedValue([]),
+}));
+jest.mock('@proton/pass/lib/shares/share.parser', () => ({
+    parseShareResponse: (...args: any[]) => mockParseShareResponse(...args),
+}));
+jest.mock('@proton/pass/lib/shares/share.requests', () => ({
+    requestShares: (...args: any[]) => mockRequestShares(...args),
+}));
+jest.mock('@proton/pass/lib/user/user.requests', () => ({
+    getUserAccess: jest.fn(),
+}));
+jest.mock('@proton/pass/lib/vaults/vault.requests', () => ({
+    createVault: (...args: any[]) => {
+        mockCallOrder.push('createVault');
+        return mockCreateVault(...args);
+    },
+}));
+jest.mock('@proton/pass/lib/vaults/vault.predicates', () => ({
+    isActiveVault: () => true,
+    isOwnVault: () => true,
+    isWritableVault: () => true,
+}));
+jest.mock('@proton/pass/utils/fp/memo', () => ({
+    maxAgeMemoize: (fn: (...args: any[]) => Promise<any>) =>
+        (async (...args: any[]) => {
+            mockCallOrder.push(`getDefault:${String(args.at(-1)?.maxAge)}`);
+            mockObservedMaxAges.push(args.at(-1)?.maxAge);
+            return fn(...args);
+        }) as any,
+}));
+jest.mock('@proton/pass/utils/fp/wait-until', () => ({
+    waitUntil: jest.fn().mockResolvedValue(true),
+}));
+
+describe('PassBridgeFactory createDefaultVault', () => {
+    beforeEach(() => {
+        jest.resetModules();
+        mockRequestShares.mockReset();
+        mockCreateVault.mockReset();
+        mockParseShareResponse.mockReset();
+        mockObservedMaxAges.length = 0;
+        mockCallOrder.length = 0;
+    });
+
+    it('uses a seven-minute getDefault precheck before creating default vault', async () => {
+        mockRequestShares.mockResolvedValue(['encrypted-share']);
+        mockParseShareResponse.mockResolvedValue(undefined);
+        mockCreateVault.mockResolvedValue({
+            shareId: 'new-vault',
+            content: { name: 'Personal' },
+        });
+
+        const { createPassBridge } = await import('@proton/pass/lib/bridge/PassBridgeFactory');
+        const bridge = createPassBridge({} as any);
+
+        await bridge.vault.createDefaultVault();
+
+        expect(mockObservedMaxAges).toEqual([UNIX_MINUTE * 7]);
+        expect(mockCallOrder).toEqual([`getDefault:${UNIX_MINUTE * 7}`, 'createVault']);
+        expect(mockCreateVault).toHaveBeenCalledTimes(1);
+        expect(mockCreateVault).toHaveBeenCalledWith({
+            content: {
+                name: 'Personal',
+                description: 'Personal vault (created from Mail)',
+                display: {},
+            },
+        });
+    });
+
+    it('returns existing vault without creating a new one', async () => {
+        const existingVault = {
+            shareId: 'existing-vault',
+            createTime: 10,
+            content: { name: 'Personal' },
+        };
+
+        mockRequestShares.mockResolvedValue(['encrypted-share']);
+        mockParseShareResponse.mockResolvedValue(existingVault);
+        mockCreateVault.mockResolvedValue({
+            shareId: 'new-vault',
+            content: { name: 'Personal' },
+        });
+
+        const { createPassBridge } = await import('@proton/pass/lib/bridge/PassBridgeFactory');
+        const bridge = createPassBridge({} as any);
+
+        const resolvedVault = await bridge.vault.createDefaultVault();
+
+        expect(mockObservedMaxAges).toEqual([UNIX_MINUTE * 7]);
+        expect(mockCallOrder).toEqual([`getDefault:${UNIX_MINUTE * 7}`]);
+        expect(resolvedVault).toEqual(existingVault);
+        expect(mockCreateVault).not.toHaveBeenCalled();
+    });
+});
